// "Preestratificación automática desde texto" — analizador local, determinista y auditable
// (ver src/local-extractor.mjs). NO es inteligencia artificial generativa y NO usa ningún
// modelo ni servicio externo: todo el análisis se ejecuta en el navegador sobre el texto
// pegado, sin ninguna solicitud de red. Sustituye por completo los commits anteriores de esta
// sección ("feat: añade extracción asistida por IA..." y "feat: extracción con IA en un solo
// paso (BYOK, sin backend)"), cuyos módulos ai-extraction.mjs, ai-providers.mjs y
// key-storage.mjs (llamadas a Azure OpenAI/OpenAI/Anthropic, gestión de claves API) se han
// eliminado íntegramente del repositorio a petición expresa: esta herramienta no contrata ni
// utiliza ningún servicio de IA generativa, gratuito o de pago.
import{DIMENSIONS,MODEL_VERSION,THRESHOLDS,VARIABLES,cumulativeInterventions,scoreCase,exportCsv,exportJson,importJson,printableReport,normalizeAnswers}from'./core.mjs';
import{analyzeClinicalText,STATUS,LIMITATIONS}from'./local-extractor.mjs';
const KEY='cmo_migrana_cases_v1';
let id=crypto.randomUUID(),pseudonym='CASO-'+Math.random().toString(36).slice(2,7).toUpperCase(),hospital='',pharmacist='',answers={},override;
// Estado de la preestratificación automática: SOLO en memoria (nunca en localStorage/sessionStorage/
// IndexedDB/cookies). Se reinicia al borrar el análisis, al recuperar otro caso o al importar un caso.
// preText: texto original pegado. preProposals: propuestas calculadas por el analizador (inmutables
// hasta el siguiente análisis). preDecisions: decisión del profesional por variable (pendiente/
// confirmada/rechazada) y valor corregido si aplica. preConfirmedVarIds/preEvidence: qué campos del
// cuestionario proceden de preestratificación confirmada (para el marcado visual "Preestratificación
// — revisar") y su fragmento justificativo.
let preOpen=false,preText='',preProposals=null,preDecisions={},preCorrectingVarIds=new Set(),preConfirmedVarIds=new Set(),preEvidence={},preLimitationsOpen=false;
function resetPreExtraction(revertAnswers){if(revertAnswers)preConfirmedVarIds.forEach(vid=>{delete answers[vid]});preText='';preProposals=null;preDecisions={};preCorrectingVarIds=new Set();preConfirmedVarIds=new Set();preEvidence={}}
const $=s=>document.querySelector(s);
const esc=s=>String(s??'').replace(/[&<>"]/g,c=>({'&':'&amp;','<':'&lt;','>':'&gt;','"':'&quot;'}[c]));
function loadCases(){return JSON.parse(localStorage.getItem(KEY)||'[]')}
function save(){const cases=loadCases().filter(c=>c.id!==id);cases.unshift({id,pseudonym,hospital,pharmacist,answers,override,updatedAt:new Date().toISOString(),trace:[{at:new Date().toISOString(),action:'autosave'}]});localStorage.setItem(KEY,JSON.stringify(cases))}
function dl(n,t,type='application/json'){const a=document.createElement('a');a.href=URL.createObjectURL(new Blob([t],{type}));a.download=n;a.click()}

const STATUS_LABEL={[STATUS.DETECTADO]:'Detectado',[STATUS.AUSENTE]:'Ausente explícitamente',[STATUS.DUDOSO]:'Dudoso / contradictorio',[STATUS.NO_MENCIONADO]:'No mencionado'};
const STATUS_CLASS={[STATUS.DETECTADO]:'pre-badge--detectado',[STATUS.AUSENTE]:'pre-badge--ausente',[STATUS.DUDOSO]:'pre-badge--dudoso',[STATUS.NO_MENCIONADO]:'pre-badge--no-mencionado'};

function runAnalysis(){if(!preText.trim()){alert('Pegue primero el texto clínico a analizar.');return}
preProposals=analyzeClinicalText(preText);
preDecisions=Object.fromEntries(preProposals.map(p=>[p.variableId,{decision:'pending',chosenValue:null}]));
preCorrectingVarIds=new Set();preOpen=true;render()}

function applyDecision(variableId,value){answers[variableId]=value;preConfirmedVarIds.add(variableId);const p=preProposals.find(x=>x.variableId===variableId);if(p&&p.evidence)preEvidence[variableId]=p.evidence}
function revertDecision(variableId){delete answers[variableId];preConfirmedVarIds.delete(variableId);delete preEvidence[variableId]}

function reviewRowHtml(p){const decision=preDecisions[p.variableId]||{decision:'pending',chosenValue:null};
const propuesta=p.proposedLabel?esc(p.proposedLabel):'—';
const fragmento=p.evidence?`“${esc(p.evidence)}”`:'—';
const puntuacion=p.previewScore!=null?`${p.previewScore} (provisional)`:'—';
let accionesHtml;
if(decision.decision==='confirmed'){
accionesHtml=`<span class="pre-decision pre-decision--confirmed">✓ Confirmado</span> <button type="button" class="pre-action" data-undo="${p.variableId}">Deshacer</button>`;
}else if(decision.decision==='rejected'){
accionesHtml=`<span class="pre-decision pre-decision--rejected">Rechazado</span> <button type="button" class="pre-action" data-reconsider="${p.variableId}">Reconsiderar</button>`;
}else if(preCorrectingVarIds.has(p.variableId)){
accionesHtml=`<select data-correct-select="${p.variableId}"><option value="">Elegir valor…</option>${p.options.map(o=>`<option value="${o.id}" ${p.proposedValue===o.id?'selected':''}>${o.label}</option>`).join('')}</select> <button type="button" class="pre-action" data-save-correction="${p.variableId}">Guardar</button> <button type="button" class="pre-action" data-cancel-correction="${p.variableId}">Cancelar</button>`;
}else if(p.status===STATUS.NO_MENCIONADO){
accionesHtml='<span class="pre-hint">Cumplimente manualmente abajo</span>';
}else{
const confirmBtn=(p.status===STATUS.DETECTADO||p.status===STATUS.AUSENTE)?`<button type="button" class="pre-action" data-confirm="${p.variableId}">Confirmar</button> `:'';
accionesHtml=`${confirmBtn}<button type="button" class="pre-action" data-correct="${p.variableId}">Corregir</button> <button type="button" class="pre-action" data-reject="${p.variableId}">${p.status===STATUS.DUDOSO?'Descartar':'Rechazar'}</button>`;
}
return`<tr class="pre-row pre-row--${p.status}"><td>${esc(p.label)}</td><td>${propuesta}</td><td><span class="pre-badge ${STATUS_CLASS[p.status]}">${STATUS_LABEL[p.status]}</span></td><td class="pre-fragment">${fragmento}</td><td class="pre-rule">${esc(p.rule)}</td><td>${puntuacion}</td><td class="pre-actions">${accionesHtml}</td></tr>`}

function reviewTableHtml(){if(!preProposals)return'<p class="pre-note">Pulse «Analizar texto» tras pegar el texto clínico para ver aquí la tabla de propuestas.</p>';
const counts=preProposals.reduce((acc,p)=>{acc[p.status]=(acc[p.status]||0)+1;return acc},{});
return`<p class="progress">Análisis completado: ${counts[STATUS.DETECTADO]||0} detectado(s), ${counts[STATUS.AUSENTE]||0} ausencia(s) explícita(s), ${counts[STATUS.DUDOSO]||0} dudoso(s)/contradictorio(s), ${counts[STATUS.NO_MENCIONADO]||0} no mencionado(s). La puntuación mostrada es <b>provisional</b>: el resultado definitivo solo se calcula tras confirmar manualmente cada variable obligatoria.</p><div class="table-scroll"><table class="pre-table"><thead><tr><th>Variable</th><th>Propuesta</th><th>Certeza</th><th>Fragmento justificativo</th><th>Regla aplicada</th><th>Puntuación (provisional)</th><th>Acciones</th></tr></thead><tbody>${preProposals.map(reviewRowHtml).join('')}</tbody></table></div>`}

function preSectionHtml(){
return`<section class="panel pre-panel"><details id="preDetails" ${preOpen?'open':''}><summary>Preestratificación automática desde texto</summary><div class="pre-body">
<p class="warning">⚠️ IMPORTANTE — Antes de pegar: evite cualquier dato identificativo del paciente (nombre, apellidos, NHC, DNI, fecha de nacimiento exacta, dirección, teléfono), aunque el análisis se ejecute íntegramente en su navegador.</p>
<p class="warning pre-local-warning">🔒 Este análisis es 100% local: se ejecuta en su navegador mediante un analizador de reglas determinista, sin inteligencia artificial generativa, sin ningún servicio externo y sin realizar ninguna solicitud de red. El texto no sale de su dispositivo y funciona sin conexión.</p>
<label>Texto clínico pegado (evolutivo/HC ya anonimizado por usted)<textarea id="preText" rows="8" placeholder="Pegue aquí el texto clínico a analizar...">${esc(preText)}</textarea></label>
<button id="analyzeBtn" type="button">Analizar texto y proponer valores</button>
<h3>Tabla de revisión</h3>
${reviewTableHtml()}
<p>Revise el cuestionario de más abajo: los campos marcados <b>«Preestratificación — revisar»</b> proceden de una propuesta confirmada y deben validarse antes de calcular la estratificación.</p>
<details id="preLimitations" ${preLimitationsOpen?'open':''}><summary>Limitaciones conocidas del analizador</summary><ul>${LIMITATIONS.map(l=>`<li>${esc(l)}</li>`).join('')}</ul></details>
<button id="resetPre" type="button">Borrar todos los datos de este análisis</button>
</div></details></section>`}

function render(){const r=scoreCase(answers,override);const completed=VARIABLES.length-r.missing.length;document.title=`CMO-Migraña P${r.finalPriority}`;$('#app').innerHTML=`<header class="hero"><div class="hero__content"><span class="badge">🏥 ${MODEL_VERSION}</span><h1>SIAF-CMO Migraña</h1><p class="subtitle">Sistema inteligente de atención farmacéutica para estratificar, priorizar y documentar pacientes con migraña.</p><p class="warning">Herramienta de apoyo a la estratificación y planificación farmacéutica. No sustituye el juicio clínico, no diagnostica, no prescribe, no recomienda cambios autónomos de tratamiento, no es producto sanitario certificado y debe validarse antes de implantación asistencial.</p><div class="chips"><span>CMO: Capacidad–Motivación–Oportunidad</span><span>Analizador local</span><span>Decisión final profesional</span></div></div><aside class="ecosystem" aria-label="Estado del caso"><h2>Estado de la valoración</h2><div class="metrics"><div><b>${completed}</b><span>variables completadas</span></div><div><b>${r.finalPriority}</b><span>prioridad final</span></div><div><b>${r.total}/${THRESHOLDS.totalMax}</b><span>puntuación</span></div><div><b>${r.missing.length}</b><span>pendientes</span></div></div><div class="ecosystem__tags"><span>MAPEX-SEFH</span><span>Práctica clínica</span><span>Informe</span></div></aside></header><section class="panel identity"><h2>1. Identificación de uso e institución</h2><div class="grid two"><label>Identificación pseudonimizada<input id="pseudo" value="${esc(pseudonym)}"></label><label>Hospital / centro sanitario<input id="hospital" value="${esc(hospital)}" placeholder="Ej. Hospital Universitario..."></label><label>Farmacéutico/a responsable<input id="pharmacist" value="${esc(pharmacist)}" placeholder="Nombre y apellidos"></label><label>Buscar casos locales<input id="search" placeholder="Buscar por pseudónimo"></label></div><div id="cases" class="case-list"></div></section>${preSectionHtml()}<section class="panel"><h2>2. Formulario por dimensiones</h2><p class="progress">Progreso: <b>${completed}/${VARIABLES.length}</b>. Los datos ausentes se muestran como pendientes y no se interpretan silenciosamente como cero.</p>${Object.entries(DIMENSIONS).map(([dim,d])=>`<fieldset><legend>${d.label} — subtotal ${r.subtotals[dim]}/${d.max}</legend>${VARIABLES.filter(v=>v.dimension===dim).map(v=>`<div class="card${preConfirmedVarIds.has(v.id)?' card--pre':''}"><label>${v.label}${preConfirmedVarIds.has(v.id)?` <span class="pre-tag" title="${esc(preEvidence[v.id]||'Procedente de preestratificación automática confirmada')}">Preestratificación — revisar</span>`:''}<select aria-label="${v.label}" data-var="${v.id}" class="${preConfirmedVarIds.has(v.id)?'pre-filled':''}"><option value="">Pendiente</option>${v.options.map(o=>`<option value="${o.id}" ${answers[v.id]===o.id?'selected':''}>${o.displayText||`${o.label} — ${o.score==null?'NA':`${o.score} puntos`}`}</option>`).join('')}</select></label><p class="field-help">${v.options.map(o=>`${o.displayText||`${o.label} — ${o.score==null?'NA':`${o.score} puntos`}`}: ${o.definition}`).join(' · ')}</p><details><summary>Definición y fuente</summary><p>${v.definition}</p><ul>${v.options.map(o=>`<li><b>${o.label}:</b> ${o.definition} (${o.score==null?'NA':`${o.score} puntos`})</li>`).join('')}</ul><small>${v.sourcePage}</small></details></div>`).join('')}</fieldset>`).join('')}</section><section class="panel"><h2>3. Resumen y resultado</h2><div class="report-meta"><span><b>Hospital:</b> ${esc(hospital)||'Pendiente'}</span><span><b>Farmacéutico/a:</b> ${esc(pharmacist)||'Pendiente'}</span></div>${r.pediatric?'<p class="alert">Menor de 18 años: Requiere valoración mediante modelo pediátrico. No se presenta clasificación adulta como clínicamente válida.</p>':''}${r.missing.length?`<p class="alert">Cálculo provisional: variables pendientes ${r.missing.join(', ')}.</p>`:''}<div class="priority p${r.finalPriority}"><b>Prioridad final: ${r.finalPriority}</b><br>Prioridad calculada: ${r.algorithmPriority}; prioridad numérica: ${r.numericPriority}; puntuación ${r.total}/${THRESHOLDS.totalMax}.</div>${r.automaticPriority?`<p>Prioridad automática: Sí. Motivo: ${r.automaticPriorityReasons.join(', ')}.</p>`:''}<h3>Contribuciones</h3><table><thead><tr><th>Variable</th><th>Opción</th><th>Puntos</th></tr></thead><tbody>${r.contributions.map(c=>`<tr><td>${c.variable}</td><td>${c.option??'Pendiente'}</td><td>${c.automaticPriorityReason?'Prioridad 1':(c.displayScore??'Sin dato')}</td></tr>`).join('')}</tbody></table><h3>Override clínico</h3><select id="override" aria-label="Nueva prioridad manual"><option value="">Sin modificación manual</option><option value="1">Prioridad 1</option><option value="2">Prioridad 2</option><option value="3">Prioridad 3</option></select>${override?`<p>Modificación manual: ${override.from} → ${override.to}. Justificación: ${override.justification}. Fecha: ${override.createdAt}. Decisión profesional ajena al algoritmo original.</p>`:''}<h3>Plan de seguimiento</h3><b>Reaplicación del modelo</b><ul>${r.periodicity.model.map(x=>`<li>${x}</li>`).join('')}</ul><b>Visitas de seguimiento</b><ul>${r.periodicity.followUp.map(x=>`<li>${x}</li>`).join('')}</ul><h3>Actuaciones farmacéuticas acumulativas</h3><ul>${cumulativeInterventions(r.finalPriority).map(i=>`<li><b>P${i.priority} · ${i.category}:</b> ${i.text}</li>`).join('')}</ul></section><section class="panel actions"><h2>4. Guardado, exportación, importación e impresión</h2><button id="save">Guardar caso</button><button id="json">Exportar JSON</button><button id="csv">Exportar CSV</button><button id="import">Importar JSON</button><button id="report">Descargar resumen clínico</button><button id="print">Imprimir informe</button><button id="del">Borrar caso</button><button id="clear">Borrar todos los datos</button></section><footer><b>Creada por Ramón Morillo Verdugo en julio de 2026.</b> Aplicación local privacy-first: sin analítica, sin APIs clínicas externas y sin envío intencionado de datos a servidores. Uso exclusivo como soporte profesional sanitario, con pseudonimización de datos, verificación clínica local, cumplimiento de RGPD/LOPDGDD, confidencialidad asistencial, registro responsable, revisión ética y validación previa a cualquier implantación asistencial.</footer>`;$('#pseudo').oninput=e=>{pseudonym=e.target.value;save()};$('#hospital').oninput=e=>{hospital=e.target.value;save()};$('#pharmacist').oninput=e=>{pharmacist=e.target.value;save()};document.querySelectorAll('[data-var]').forEach(x=>x.onchange=e=>{answers[e.target.dataset.var]=e.target.value||undefined;preConfirmedVarIds.delete(e.target.dataset.var);save();render()});$('#override').onchange=e=>{const to=+e.target.value;if(to){const rr=scoreCase(answers);const justification=prompt('Justificación clínica obligatoria')||'';if(justification.trim()){override={from:rr.algorithmPriority,to,justification,createdAt:new Date().toISOString(),reinforcedWarningAccepted:!!(rr.automaticPriority&&to>rr.algorithmPriority)};save();render()}}};$('#save').onclick=()=>{save();alert('Caso guardado')};$('#json').onclick=()=>dl('caso-cmo-migrana.json',exportJson({id,pseudonym,hospital,pharmacist,answers,override,result:r}));$('#csv').onclick=()=>dl('caso-cmo-migrana.csv',exportCsv([{id,pseudonym,hospital,pharmacist,total:r.total,prioridad:r.finalPriority,status:r.status}]),'text/csv');$('#import').onclick=()=>{const text=prompt('Pegue JSON importado');if(text){const c=importJson(text);id=c.id||crypto.randomUUID();pseudonym=c.pseudonym||'CASO-IMPORTADO';hospital=c.hospital||'';pharmacist=c.pharmacist||'';answers=normalizeAnswers(c.answers||{});override=c.override;resetPreExtraction(false);save();render()}};$('#report').onclick=()=>dl('informe-cmo-migrana.txt',printableReport({pseudonym,hospital,pharmacist,answers,override}),'text/plain');$('#print').onclick=()=>print();$('#del').onclick=()=>{if(confirm('¿Borrar este caso?')){localStorage.setItem(KEY,JSON.stringify(loadCases().filter(c=>c.id!==id)));alert('Borrado')}};$('#clear').onclick=()=>confirm('¿Borrar todos los datos locales?')&&localStorage.removeItem(KEY);$('#search').oninput=e=>{$('#cases').innerHTML=loadCases().filter(c=>c.pseudonym.toLowerCase().includes(e.target.value.toLowerCase())).slice(0,5).map(c=>`<button data-load="${c.id}">Recuperar ${esc(c.pseudonym)}</button>`).join('');document.querySelectorAll('[data-load]').forEach(b=>b.onclick=()=>{const c=loadCases().find(x=>x.id===b.dataset.load);id=c.id;pseudonym=c.pseudonym;hospital=c.hospital||'';pharmacist=c.pharmacist||'';answers=normalizeAnswers(c.answers);override=c.override;resetPreExtraction(false);render()})};
$('#preText').oninput=e=>{preText=e.target.value};
$('#preDetails').ontoggle=e=>{preOpen=e.target.open};
$('#preLimitations').ontoggle=e=>{preLimitationsOpen=e.target.open};
$('#analyzeBtn').onclick=()=>runAnalysis();
document.querySelectorAll('[data-confirm]').forEach(b=>b.onclick=()=>{const vid=b.dataset.confirm;const p=preProposals.find(x=>x.variableId===vid);applyDecision(vid,p.proposedValue);preDecisions[vid]={decision:'confirmed',chosenValue:p.proposedValue};save();render()});
document.querySelectorAll('[data-reject]').forEach(b=>b.onclick=()=>{const vid=b.dataset.reject;preDecisions[vid]={decision:'rejected',chosenValue:null};render()});
document.querySelectorAll('[data-undo]').forEach(b=>b.onclick=()=>{const vid=b.dataset.undo;revertDecision(vid);preDecisions[vid]={decision:'pending',chosenValue:null};save();render()});
document.querySelectorAll('[data-reconsider]').forEach(b=>b.onclick=()=>{const vid=b.dataset.reconsider;preDecisions[vid]={decision:'pending',chosenValue:null};render()});
document.querySelectorAll('[data-correct]').forEach(b=>b.onclick=()=>{preCorrectingVarIds.add(b.dataset.correct);render()});
document.querySelectorAll('[data-cancel-correction]').forEach(b=>b.onclick=()=>{preCorrectingVarIds.delete(b.dataset.cancelCorrection);render()});
document.querySelectorAll('[data-save-correction]').forEach(b=>b.onclick=()=>{const vid=b.dataset.saveCorrection;const select=$(`select[data-correct-select="${vid}"]`);const value=select?select.value:'';if(!value){alert('Elija un valor antes de guardar.');return}applyDecision(vid,value);preDecisions[vid]={decision:'confirmed',chosenValue:value};preCorrectingVarIds.delete(vid);save();render()});
$('#resetPre').onclick=()=>{if(confirm('¿Borrar el texto analizado, las propuestas y los campos confirmados por preestratificación?')){resetPreExtraction(true);preOpen=true;save();render()}}}
render();save();
